#!/usr/bin/env python3
import argparse,json,sys
from pathlib import Path
ap=argparse.ArgumentParser(); ap.add_argument('--root',default='.'); ap.add_argument('--out',default='outputs/source_mapping_check.json'); a=ap.parse_args(); r=Path(a.root); snaps=json.loads((r/'rules/original_rule_snapshots.json').read_text(encoding='utf-8'))['items']; src=sorted(set(x['source'] for x in snaps)); mapping=(r/'SOURCE_SENTENCE_TO_SKILL_RULE.md').read_text(encoding='utf-8',errors='ignore') if (r/'SOURCE_SENTENCE_TO_SKILL_RULE.md').exists() else ''; covered=[s for s in src if s in mapping or Path(s).name in mapping]; out={'snapshot_rules':len(snaps),'source_files':len(src),'covered_source_files_in_mapping':len(covered),'uncovered_examples':[s for s in src if s not in covered][:50],'status':'needs_review' if len(covered)<len(src) else 'covered'}; Path(a.out).parent.mkdir(parents=True,exist_ok=True); Path(a.out).write_text(json.dumps(out,ensure_ascii=False,indent=2),encoding='utf-8'); print(json.dumps(out,ensure_ascii=False,indent=2)); sys.exit(0 if out['status']=='covered' else 3)
